// Backward-compatible aliases for older engine references.
window.easyConceptPools = window.microSkillRepairPools;
window.mediumConceptPools = window.microSkillBridgePools;

// Quick validation in the browser console. This is not the engine. It is a guardrail.
(function validateCostDirectiveBank(){
  const banks = window.questionBanks || {};
  const ids = [];
  const texts = [];
  const allQuestions = [];
  Object.values(banks).forEach(pool => {
    if(Array.isArray(pool)) pool.forEach(q => { ids.push(q.id); texts.push(q.q); allQuestions.push(q); });
  });
  Object.values(window.microSkillRepairPools || {}).forEach(pool => {
    if(Array.isArray(pool)) pool.forEach(q => { ids.push(q.id); texts.push(q.q); allQuestions.push(q); });
  });
  Object.values(window.microSkillBridgePools || {}).forEach(pool => {
    if(Array.isArray(pool)) pool.forEach(q => { ids.push(q.id); texts.push(q.q); allQuestions.push(q); });
  });
  const duplicateIds = ids.filter((id, index) => ids.indexOf(id) !== index);
  const duplicateTexts = texts.filter((text, index) => texts.indexOf(text) !== index);
  const answerPositions = allQuestions.reduce((acc, q) => { acc[q.a] = (acc[q.a] || 0) + 1; return acc; }, {});
  if(duplicateIds.length){
    console.warn("Cost Directive duplicate question IDs detected:", [...new Set(duplicateIds)]);
  }
  if(duplicateTexts.length){
    console.warn("Cost Directive duplicate question text detected:", [...new Set(duplicateTexts)].slice(0, 25));
  }
  console.log("Cost Directive question bank loaded", {
    easy: banks.easy?.length || 0,
    medium: banks.medium?.length || 0,
    hard: banks.hard?.length || 0,
    elite: banks.elite?.length || 0,
    legendary: banks.legendary?.length || 0,
    easyBoss: banks.easyBoss?.length || 0,
    mediumBoss: banks.mediumBoss?.length || 0,
    finalBoss: banks.finalBoss?.length || 0,
    legendaryBoss: banks.legendaryBoss?.length || 0,
    repairQuestions: Object.values(window.microSkillRepairPools || {}).reduce((n,p)=> n + (Array.isArray(p) ? p.length : 0), 0),
    bridgeQuestions: Object.values(window.microSkillBridgePools || {}).reduce((n,p)=> n + (Array.isArray(p) ? p.length : 0), 0),
    repairPools: Object.keys(window.microSkillRepairPools || {}).length,
    bridgePools: Object.keys(window.microSkillBridgePools || {}).length,
    answerPositions
  });
})();
